const body = $json.body;
const messages = body?.entry?.[0]?.changes?.[0]?.value?.messages;
if (!messages || messages.length === 0) {
  return [];
}
const msg = messages[0];
if (msg.type !== 'text') {
  return [];
}
return [{
  sessionId: msg.from,
  message: msg.text.body,
  from: msg.from
}];

const output = $json.output || "¡Hola!";
let sessionId = "web-user";
try {
  sessionId = $("Webhook").first().json.body.sessionId || "web-user";
} catch (e) {}
return { reply: output, sessionId: sessionId };
